patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 56bd79f41460..013b867ef54d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2542,6 +2542,9 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       AbsSign->copyFastMathFlags(II);
       return replaceInstUsesWith(*II, AbsSign);
     }
+    Value *X;
+    if (match(II->getArgOperand(0), m_FNeg(m_Value(X))))
+      return replaceOperand(*II, 0, X);

     [[fallthrough]];
   }

